<?php/** * AquaLuxe Admin * * @package AquaLuxe * @since 1.0.0 */// Prevent direct access to this fileif (!defined('ABSPATH')) {    exit;}/** * AquaLuxe_Admin Class */class AquaLuxe_Admin {    /**     * Constructor     */    public function __construct() {        // Add admin menu        add_action('admin_menu', array($this, 'add_admin_menu'));                // Add admin scripts and styles        add_action('admin_enqueue_scripts', array($this, 'enqueue_admin_scripts'));                // Add theme info to admin footer        add_filter('admin_footer_text', array($this, 'admin_footer_text'));                // Add dashboard widgets        add_action('wp_dashboard_setup', array($this, 'add_dashboard_widgets'));                // Add admin notices        add_action('admin_notices', array($this, 'admin_notices'));                // Add meta boxes        add_action('add_meta_boxes', array($this, 'add_meta_boxes'));                // Save meta box data        add_action('save_post', array($this, 'save_meta_box_data'));                // Add theme options        add_action('admin_init', array($this, 'register_settings'));    }}